
USE superstore;


CREATE TABLE IF NOT EXISTS sales (
  `Order_ID` TEXT,
  `Order_Date` TEXT,
  `Customer_Name` TEXT,
  `Region` TEXT,
  `Category` TEXT,
  `Sales` TEXT,
  `Quantity` TEXT,
  `Profit` TEXT,
  `Discount` TEXT
);


SELECT COUNT(*) FROM sales;
USE superstore ; 
SELECT Region , SUM(sales) AS Total_sales
FROM sales
GROUP BY REGION ; 

## Top five profitable product 

SELECT Category, SUM(Profit) AS Total_Profit
FROM sales
GROUP BY Category 
ORDER BY total_profit DESC
Limit 5 ; 

## Monthly Sales Trend 
SELECT MONTH(STR_TO_DATE(Order_Date,'%d-%m-%Y')) AS month,
       SUM(CAST(Sales AS DECIMAL(10,2))) AS total_sales
FROM sales
GROUP BY month
ORDER BY month;

### Highest discount impact 

SELECT discount , AVG(profit)
FROM sales
GROUP BY discount ; 